{
    public static bool IsPending(this OrderStatus status)
    {
        return status == OrderStatus.Pending;
    }

    public static bool IsShipped(this OrderStatus status)
    {
        return status == OrderStatus.Shipped;
    }

    public static bool IsDelivered(this OrderStatus status)
    {
        return status == OrderStatus.Delivered;
    }

    public static bool IsCancelled(this OrderStatus status)
    {
        return status == OrderStatus.Cancelled;
    }

    public static bool IsCompleted(this OrderStatus status)
    {
        return status == OrderStatus.Delivered || status == OrderStatus.Cancelled;
    }

    public static bool IsCancelable(this OrderStatus status)
    {
        return status == OrderStatus.Pending || status == OrderStatus.Shipped;
    }
}
```

